/* ==========================================================================
   ToggleButtonGroup — flush row of ds-toggle-button components.
   The group container carries the elevation; individual button chrome
   (shadow/border) is suppressed via .item.
   ========================================================================== */

.group {
  display: inline-flex;
  align-items: stretch;
  border-radius: var(--dimension-radius-050);
  position: relative;
}

/* Inset ring / highlight overlay — sits above button children */
.group::after {
  content: '';
  position: absolute;
  inset: 0;
  border-radius: inherit;
  pointer-events: none;
}

/* ── Group-level elevation ──────────────────────────────────────────────── */

.groupElevated { box-shadow: var(--effect-shadow-elevated-sm); }
.groupElevated::after { box-shadow: var(--effect-highlight-elevated-sm); }

.groupFlat::after { box-shadow: inset 0 0 0 1px var(--color-border-tertiary); }

.groupFloating { box-shadow: var(--effect-shadow-elevated-floating); }
.groupFloating::after { box-shadow: var(--effect-highlight-elevated-floating); }

/* groupNone = ghost — no shadow, no border */

.groupRounded { border-radius: var(--dimension-radius-half); }

/* ── Base item ─────────────────────────────────────────────────────────────── */

.item {
  flex-shrink: 0;
  /* Suppress individual elevation so the group reads as one unit */
  box-shadow: none !important;
  border: none !important;
  /* Suppress scale-on-press to avoid gaps at the divider */
}

.item:active {
  transform: none !important;
}

/* ── Divider ──────────────────────────────────────────────────────────────── */

/* Full-height divider (elevated / flat / floating) */
.divider {
  width: 1px;
  flex-shrink: 0;
  background-color: var(--color-border-tertiary);
  position: relative;
  z-index: 1;
  margin: 0 -0.5px;
  pointer-events: none;
}

/* Ghost: short centred divider at icon height */
.dividerGhost    { height: 20px; align-self: center; }
.dividerGhostXS  { height: 12px; }
.dividerGhostSM  { height: 16px; }

/* Ghost hover-fade: hide divider adjacent to hovered ghost button */
.item:hover + .dividerGhost,
.dividerGhost:has(+ .item:hover) { opacity: 0; }

/* Ghost pressed-state: hide divider adjacent to selected button */
.itemPressed + .dividerGhost,
.dividerGhost:has(+ .itemPressed) { opacity: 0; }

/* ── Ghost interaction states: rounded chips ──────────────────────────────── */

.group .itemShort::after {
  border-top-left-radius:     var(--dimension-radius-050) !important;
  border-top-right-radius:    var(--dimension-radius-050) !important;
  border-bottom-right-radius: var(--dimension-radius-050) !important;
  border-bottom-left-radius:  var(--dimension-radius-050) !important;
}

.group .itemPressed {
  border-top-left-radius:     var(--dimension-radius-050) !important;
  border-top-right-radius:    var(--dimension-radius-050) !important;
  border-bottom-right-radius: var(--dimension-radius-050) !important;
  border-bottom-left-radius:  var(--dimension-radius-050) !important;
}

/* ── Border radius: flatten inner-facing corners ──────────────────────────── */

.first {
  border-top-right-radius:    0 !important;
  border-bottom-right-radius: 0 !important;
}

.last {
  border-top-left-radius:    0 !important;
  border-bottom-left-radius: 0 !important;
}

.middle {
  border-radius: 0 !important;
}

/* Rounded group: first — left corners become pill */
.groupRounded .first.itemShort::after,
.groupRounded .first.itemPressed {
  border-top-left-radius:    var(--dimension-radius-half) !important;
  border-bottom-left-radius: var(--dimension-radius-half) !important;
}

/* Rounded group: last — right corners become pill */
.groupRounded .last.itemShort::after,
.groupRounded .last.itemPressed {
  border-top-right-radius:    var(--dimension-radius-half) !important;
  border-bottom-right-radius: var(--dimension-radius-half) !important;
}

/* ── Rounded: inner-edge padding correction ──────────────────────────────── */

/* MD — base padding: space-100 */
.roundedFirstMD { padding-right: var(--dimension-space-100) !important; }
.roundedLastMD  { padding-left:  var(--dimension-space-100) !important; }
.roundedMidMD   { padding-left:  var(--dimension-space-100) !important; padding-right: var(--dimension-space-100) !important; }

/* SM — base padding: space-075 */
.roundedFirstSM { padding-right: var(--dimension-space-075) !important; }
.roundedLastSM  { padding-left:  var(--dimension-space-075) !important; }
.roundedMidSM   { padding-left:  var(--dimension-space-075) !important; padding-right: var(--dimension-space-075) !important; }

import { Component, Prop, Event, EventEmitter, h, Host } from '@stencil/core';

export type ToggleGroupElevation  = 'none' | 'flat' | 'elevated' | 'floating';
export type ToggleGroupSize       = 'md' | 'sm' | 'xs';
export type ToggleGroupBackground = 'faint' | 'medium' | 'bold' | 'strong' | 'always-dark';

export interface ToggleGroupItem {
  id: string;
  label?: string;
  /** Icon name for <ds-icon>. */
  icon?: string;
  inactive?: boolean;
}

@Component({
  tag: 'ds-toggle-button-group',
  styleUrl: 'ToggleButtonGroup.css',
  scoped: true,
})
export class ToggleButtonGroup {
  /**
   * Array of item descriptors. Set via JS property.
   * @example el.items = [{ id: 'list', label: 'List' }, { id: 'grid', icon: 'GridView' }];
   */
  @Prop() items: ToggleGroupItem[] = [];

  /** ID of the currently selected / pressed item. */
  @Prop({ mutable: true }) value: string = '';

  /** Chrome level for the group container. */
  @Prop() elevation: ToggleGroupElevation = 'elevated';

  /** Size passed to each ds-toggle-button. */
  @Prop() size: ToggleGroupSize = 'md';

  /** Pill shape for group + buttons. */
  @Prop() rounded: boolean = false;

  /** Parent surface context. */
  @Prop() background: ToggleGroupBackground | undefined;

  /** Emits the id of the newly selected item. */
  @Event() dsChange!: EventEmitter<string>;

  private handleItemChange(id: string) {
    if (id === this.value) return;
    this.value = id;
    this.dsChange.emit(id);
  }

  render() {
    const items = this.items;
    const count = items.length;
    const elev = this.elevation;
    const elevKey = elev.charAt(0).toUpperCase() + elev.slice(1);
    const bg = this.background;
    const isGhost = elev === 'none';

    const groupCls: Record<string, boolean> = {
      group: true,
      [`group${elevKey}`]: true,
      groupRounded: this.rounded,
    };

    return (
      <Host>
        <div class={groupCls} role="group">
          {items.map((item, i) => {
            const isFirst = i === 0;
            const isLast = i === count - 1;
            const isMid = !isFirst && !isLast;
            const isPressed = item.id === this.value;
            const isIconOnly = !!item.icon && !item.label;
            const needsRoundedCorrection = this.rounded && !isIconOnly && this.size !== 'xs';
            const sizeKey = this.size.toUpperCase() as 'MD' | 'SM' | 'XS';

            const itemCls: Record<string, boolean> = {
              item: true,
              first: isFirst,
              last: isLast,
              middle: isMid,
              itemShort: isGhost,
              itemPressed: isGhost && isPressed,
              [`roundedFirst${sizeKey}`]: !!(needsRoundedCorrection && isFirst),
              [`roundedLast${sizeKey}`]: !!(needsRoundedCorrection && isLast),
              [`roundedMid${sizeKey}`]: !!(needsRoundedCorrection && isMid),
            };

            const dividerCls: Record<string, boolean> = {
              divider: true,
              dividerGhost: isGhost,
              dividerGhostXS: isGhost && this.size === 'xs',
              dividerGhostSM: isGhost && this.size === 'sm',
            };

            return [
              i > 0 && (
                <div class={dividerCls} aria-hidden="true" />
              ),
              <ds-toggle-button
                class={itemCls}
                elevation={elev}
                size={this.size}
                label={item.label}
                icon={item.icon}
                rounded={this.rounded}
                background={bg}
                pressed={isPressed}
                inactive={item.inactive}
                onDsChange={() => this.handleItemChange(item.id)}
              />,
            ];
          })}
        </div>
      </Host>
    );
  }
}
